 1	import React, { FC, useEffect } from 'react';
 2	
 3	import { SecretModel } from '@kubevirt-ui/kubevirt-api/console';
 4	import { IoK8sApiCoreV1Secret } from '@kubevirt-ui/kubevirt-api/kubernetes';
 5	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 6	import useKubevirtUserSettings from '@kubevirt-utils/hooks/useKubevirtUserSettings/useKubevirtUserSettings';
 7	import useRHELAutomaticSubscription from '@kubevirt-utils/hooks/useRHELAutomaticSubscription/useRHELAutomaticSubscription';
 8	import {
 9	  getGroupVersionKindForModel,
10	  useK8sWatchResource,
11	} from '@openshift-console/dynamic-plugin-sdk';
12	import { Stack, StackItem, Title } from '@patternfly/react-core';
13	
14	import { useDrawerContext } from './hooks/useDrawerContext';
15	import { TemplatesCatalogDrawerCreateForm } from './TemplatesCatalogDrawerCreateForm';
16	import { TemplatesCatalogDrawerFooterSkeleton } from './TemplatesCatalogDrawerFooterSkeleton';
17	
18	type TemplateCatalogDrawerFooterProps = {
19	  namespace: string;
20	  onCancel: () => void;
21	};
22	
23	export const TemplatesCatalogDrawerFooter: FC<TemplateCatalogDrawerFooterProps> = ({
24	  namespace,
25	  onCancel,
26	}) => {
27	  const { t } = useKubevirtTranslation();
28	  const [authorizedSSHKeys, updateAuthorizedSSHKeys, userSettingsLoaded] =
29	    useKubevirtUserSettings('ssh');
30	  const { loaded: loadedRHELSubscription, subscriptionData } = useRHELAutomaticSubscription();
31	  const { templateDataLoaded, templateLoadingError } = useDrawerContext();
32	
33	  const [, , loadError] = useK8sWatchResource<IoK8sApiCoreV1Secret>(
34	    authorizedSSHKeys?.[namespace] && {
35	      groupVersionKind: getGroupVersionKindForModel(SecretModel),
36	      isList: false,
37	      name: authorizedSSHKeys?.[namespace],
38	      namespace,
39	    },
40	  );
41	
42	  useEffect(() => {
43	    // if an error exists it means the secret can not be reached and should be removed from user settings
44	    if (loadError && authorizedSSHKeys?.[namespace]) {
45	      updateAuthorizedSSHKeys({ ...authorizedSSHKeys, [namespace]: '' });
46	    }
47	  }, [authorizedSSHKeys, loadError, namespace, updateAuthorizedSSHKeys]);
48	
49	  const loaded = templateDataLoaded && userSettingsLoaded && loadedRHELSubscription;
50	
51	  if (!loaded && !templateLoadingError) {
52	    return <TemplatesCatalogDrawerFooterSkeleton />;
53	  }
54	
55	  return (
56	    <Stack className="template-catalog-drawer-info">
57	      <div className="template-catalog-drawer-footer-section">
58	        <Stack hasGutter>
59	          <StackItem>
60	            <Title headingLevel="h1" size="lg">
61	              {t('Quick create VirtualMachine')}
62	            </Title>
63	          </StackItem>
64	          <TemplatesCatalogDrawerCreateForm
65	            authorizedSSHKey={!loadError && authorizedSSHKeys?.[namespace]}
66	            namespace={namespace}
67	            onCancel={onCancel}
68	            subscriptionData={subscriptionData}
69	          />
70	        </Stack>
71	      </div>
72	    </Stack>
73	  );
74	};

